
INSERT INTO faqs (id, category_id, question, answer, display_order, is_published)
VALUES
-- BOOKING & PAYMENTS
('a1016001-0000-4000-8000-000000000001', 'cc000001-0000-4000-8000-000000000001', 'How do I book a tour package with Divine Travel?', 'You can book directly through our website by selecting your preferred package and filling the enquiry form. Our travel consultant will contact you within 2 hours to confirm availability, customize your itinerary, and process payment. You can also call or WhatsApp our 24/7 helpline.', 1, true),
('a1016002-0000-4000-8000-000000000002', 'cc000001-0000-4000-8000-000000000001', 'What payment methods do you accept?', 'We accept all major credit and debit cards (Visa, Mastercard, RuPay), UPI (GPay, PhonePe, Paytm), net banking, and bank transfers (NEFT/RTGS/IMPS). For international tours, we also accept payments in USD via international wire transfer. EMI options are available on major credit cards for packages above Rs. 25,000.', 2, true),
('a1016003-0000-4000-8000-000000000003', 'cc000001-0000-4000-8000-000000000001', 'How much advance payment is required to confirm a booking?', 'For domestic tour packages, we require a 25% advance payment at the time of booking confirmation. The remaining 75% must be paid 15 days before departure. For international packages, 30% is required at booking and the balance 30 days before departure. Airport transfer bookings require full payment at booking.', 3, true),
('a1016004-0000-4000-8000-000000000004', 'cc000001-0000-4000-8000-000000000001', 'What is your cancellation policy?', 'Cancellation charges apply based on notice period: 45+ days before departure — 10% of package cost. 30-44 days — 25%. 15-29 days — 50%. 7-14 days — 75%. Less than 7 days — 100% (no refund). For certain peak season bookings (Char Dham, Tirupati Brahmotsavam), specific cancellation terms apply as stated in the booking confirmation.', 4, true),
('a1016005-0000-4000-8000-000000000005', 'cc000001-0000-4000-8000-000000000001', 'Can I modify my booking after confirmation?', 'Yes, booking modifications are allowed subject to availability. Changes made more than 30 days before departure are generally free of charge. Changes within 30 days may attract amendment fees of Rs. 500-2,000 depending on the type of change. Date changes, hotel upgrades, and route modifications are handled on a case-by-case basis by our team.', 5, true),
('a1016006-0000-4000-8000-000000000006', 'cc000001-0000-4000-8000-000000000001', 'Do you provide travel insurance?', 'We strongly recommend travel insurance for all tours. We partner with leading insurers to offer comprehensive coverage including medical emergencies, trip cancellation, baggage loss, and flight delays. Insurance can be added at booking. For international tours and adventure/pilgrimage packages (especially Char Dham and Himalayan treks), insurance is highly recommended.', 6, true),
('a1016007-0000-4000-8000-000000000007', 'cc000001-0000-4000-8000-000000000001', 'How do I get my booking confirmation?', 'Upon payment of the advance, you will receive a detailed booking confirmation email within 2 hours. This includes your tour itinerary, hotel vouchers, guide contact details, pickup timing, and important notes. A WhatsApp copy is also sent to your registered mobile number. Please save this confirmation as it may be required at hotels and temple queue counters.', 7, true),
('a1016008-0000-4000-8000-000000000008', 'cc000001-0000-4000-8000-000000000001', 'Is GST included in the package price?', 'All package prices displayed on our website are inclusive of 5% GST as applicable under Indian tax law for tour packages. Airport transfers are charged at 5% GST. A detailed GST invoice is provided with every booking. If your company requires a GST invoice for ITC, please provide your GSTIN at the time of booking.', 8, true),
('a1016009-0000-4000-8000-000000000009', 'cc000001-0000-4000-8000-000000000001', 'Do you offer group discounts?', 'Yes! Groups of 8 or more passengers receive a 10% discount on package price. Groups of 15+ receive 15% discount. Groups of 25+ receive up to 20% discount. Corporate groups and pilgrimage groups can contact our dedicated group travel desk for customized pricing. School and college educational tours receive special rates.', 9, true),
('a1016010-0000-4000-8000-000000000010', 'cc000001-0000-4000-8000-000000000001', 'Can I get a customized package?', 'Absolutely! Customization is our specialty. Tell us your preferred destinations, travel dates, budget, number of travelers, and special requirements. Our travel experts will design a bespoke itinerary within 24 hours. Custom packages cover accommodation category preference, meal preferences (vegetarian/Jain/diabetic), and mobility requirements.', 10, true),

-- PILGRIMAGE TOURS
('a2016001-0000-4000-8000-000000000001', 'cc000002-0000-4000-8000-000000000002', 'How far in advance should I book the Char Dham Yatra?', 'We recommend booking at least 3-4 months in advance, especially for the peak season (May-June). Online registration on the Uttarakhand government portal is mandatory and should be done simultaneously. Char Dham helicopter packages are extremely limited and often sold out 6 months in advance. Fixed departure group tours fill up 2-3 months before travel.', 1, true),
('a2016002-0000-4000-8000-000000000002', 'cc000002-0000-4000-8000-000000000002', 'What is the best time to visit Tirupati?', 'Tirupati can be visited year-round. The best months are October to February when the weather is pleasant (20-30°C). The Brahmotsavam festival (September-October, 9 days) is the most spiritually significant time but also the most crowded. Weekdays are significantly less crowded than weekends. We recommend Tuesday to Thursday visits for shorter queues.', 2, true),
('a2016003-0000-4000-8000-000000000003', 'cc000002-0000-4000-8000-000000000002', 'Are there age restrictions for Char Dham Yatra?', 'The Uttarakhand government recommends that travelers above 60 years and below 12 years obtain medical clearance before registering for the Yatra. The Kedarnath trek (16km) requires reasonable physical fitness. Pony and palanquin services are available for those who cannot trek. Pregnant women should avoid the high-altitude portions (Kedarnath, Badrinath at 3133m and 3133m respectively).', 3, true),
('a2016004-0000-4000-8000-000000000004', 'cc000002-0000-4000-8000-000000000002', 'What documents are needed for pilgrimage packages?', 'For most domestic pilgrimage tours, an Aadhaar card or valid photo ID is sufficient. For Char Dham, the online registration card (downloaded from the Uttarakhand portal) must be carried. For Sabarimala, Aadhaar card is required. We handle all VIP darshan booking documents on your behalf and provide them before departure. For international pilgrimage, passport is required.', 4, true),
('a2016005-0000-4000-8000-000000000005', 'cc000002-0000-4000-8000-000000000002', 'Do your pilgrimage packages include VIP darshan?', 'Yes, all our pilgrimage packages include VIP/Special Darshan arrangements. For Tirupati, we book Special Entry Darshan (SED) tickets 90+ days in advance. For Shirdi, we arrange priority queue access. For Varanasi Kashi Vishwanath, we use the temple''s official VIP booking system. This eliminates 8-20 hour general queue waits. VIP darshan charges are included in the package price.', 5, true),
('a2016006-0000-4000-8000-000000000006', 'cc000002-0000-4000-8000-000000000002', 'Can non-Hindus join pilgrimage tours?', 'Certain temples restrict entry to Hindus only (Tirupati, Guruvayur, Sabarimala, Puri Jagannath). At these sites, non-Hindu companions cannot enter the main sanctum but can explore the outer complex and local area. Tours like Varanasi ghats, Golden Temple Amritsar, Rameswaram, and Haridwar-Rishikesh are open to all faiths. Please check individual tour descriptions.', 6, true),
('a2016007-0000-4000-8000-000000000007', 'cc000002-0000-4000-8000-000000000002', 'What is included in Char Dham Yatra package?', 'Our 11-day Char Dham Yatra package includes: 10 nights accommodation, all meals (breakfast/lunch/dinner), AC vehicle from Haridwar to Haridwar, experienced Himalayan guide, pony/palanquin arrangements at Kedarnath and Yamunotri, medical kit with oxygen cylinder, Inner Line Permits, and emergency support. Airfare to Haridwar and personal expenses are excluded.', 7, true),
('a2016008-0000-4000-8000-000000000008', 'cc000002-0000-4000-8000-000000000002', 'How do I prepare for altitude sickness on Char Dham?', 'Start acclimatizing 2-3 months before by walking 5-7km daily. Arrive at Haridwar 2 days before the yatra begins. Rest on arrival at high altitudes. Drink 4+ liters of water daily. Avoid alcohol. Eat light vegetarian meals. Diamox (125mg twice daily) can be taken preventively — consult your doctor first. If AMS symptoms appear (headache, nausea, dizziness, breathlessness), descend immediately. Never ascend with AMS symptoms.', 8, true),
('a2016009-0000-4000-8000-000000000009', 'cc000002-0000-4000-8000-000000000002', 'Are meals vegetarian on pilgrimage tours?', 'All meals on pilgrimage tours are 100% pure vegetarian — no meat, fish, or eggs. In temple towns, we follow traditional Sattvic diet (no onion or garlic). We accommodate Jain dietary requirements (no root vegetables) on request. All restaurants are vetted for hygiene and authenticity. Homemade-style Tamil, Telugu, and Kannada meals are specifically arranged for our South Indian pilgrims on South India temple tours.', 9, true),
('a2016010-0000-4000-8000-000000000010', 'cc000002-0000-4000-8000-000000000002', 'Do you arrange special poojas and sevas at temples?', 'Yes! We arrange special poojas, abhishekams, and sevas at major temples with advance booking. At Tirupati: Suprabhatham, Thomala Seva. At Varanasi: Rudrabhishek. At Rameswaram: Maha Abhishek with sea water. At Shirdi: Kakad Aarti seva. These must be requested at least 45 days in advance as seva slots are extremely limited and demand is high, especially for popular timings.', 10, true),

-- VEHICLE RENTALS
('a3016001-0000-4000-8000-000000000001', 'cc000003-0000-4000-8000-000000000003', 'What types of vehicles are available for rent?', 'We offer a comprehensive fleet: Hatchbacks (Swift, i20) for city travel, Sedans (Dzire, Etios) for 4-person comfort, SUVs (Innova, Crysta, Ertiga) for families and mountain routes, Tempo Travellers (12-17 seaters) for groups, Coaches (27-49 seaters) for large groups, and Luxury vehicles (BMW, Mercedes) for VIP transfers. All vehicles are air-conditioned, GPS-tracked, and commercially licensed.', 1, true),
('a3016002-0000-4000-8000-000000000002', 'cc000003-0000-4000-8000-000000000003', 'What is included in the vehicle rental price?', 'Our rental price includes: driver, fuel, inter-state permits, driver allowance, and 5% GST. Toll charges, parking fees, and state entry taxes (where applicable) are borne by the passenger. For outstation trips, a driver night halt allowance of Rs. 250/night applies when the driver stays outside the base city.', 2, true),
('a3016003-0000-4000-8000-000000000003', 'cc000003-0000-4000-8000-000000000003', 'Are your vehicles suitable for mountain routes?', 'Yes. For Himalayan routes (Char Dham, Leh Ladakh, Manali, Spiti), we use specially maintained high-clearance vehicles — Mahindra Bolero, Force Cruiser, or Toyota Innova. All mountain vehicles are serviced within 7 days before the trip, carry basic repair tools, and have experienced drivers with 3+ years of mountain driving. 4WD vehicles are available for extreme routes like Spiti, Zanskar, and Pin Valley.', 3, true),
('a3016004-0000-4000-8000-000000000004', 'cc000003-0000-4000-8000-000000000003', 'Can I hire a vehicle for multiple days?', 'Yes, outstation multi-day vehicle hire is available for 1-30 days. Rates are calculated per km (Rs. 11-18/km depending on vehicle type) with a minimum 300km per day. Full-day (12-hour, 300km) and half-day (6-hour, 150km) packages are also available for local city sightseeing. Driver bata of Rs. 300/day applies for outstation overnight trips.', 4, true),
('a3016005-0000-4000-8000-000000000005', 'cc000003-0000-4000-8000-000000000003', 'Are your drivers verified and trained?', 'All our drivers undergo a 5-step verification process: police verification, commercial driving license validation, background check, defensive driving training, and customer service orientation. Drivers are also trained in basic first aid and vehicle maintenance. We maintain a performance rating system — drivers below 4.0/5.0 rating are retrained or removed from the fleet.', 5, true),

-- HOTEL ASSISTANCE
('a4016001-0000-4000-8000-000000000001', 'cc000004-0000-4000-8000-000000000004', 'Do you assist with standalone hotel bookings?', 'Yes! Our hotel assistance service helps you book the right hotel even without a full package. We have negotiated rates at 500+ hotels across India and 20+ international destinations — from budget temple-adjacent guesthouses to 5-star resorts. Our recommendations are based on actual experience, not just aggregator listings.', 1, true),
('a4016002-0000-4000-8000-000000000002', 'cc000004-0000-4000-8000-000000000004', 'Can you arrange temple-adjacent accommodation?', 'Yes, this is our specialty. For Tirupati, we book hotels within 1km of the TTD complex or at Tirumala directly. For Shirdi, within 200 meters of the Samadhi Mandir. For Varanasi, guesthouses on the ghats. For Char Dham, certified pilgrim lodges at each shrine. Proximity to the temple is always our priority for pilgrimage accommodation.', 2, true),

-- GENERAL
('a5016001-0000-4000-8000-000000000001', 'cc000005-0000-4000-8000-000000000005', 'What makes Divine Travel different?', 'Divine Travel specializes in spiritual and experiential travel for South Indian customers. Key differentiators: deep expertise in temple circuits (our founders are devout pilgrims themselves), 24/7 on-trip support, all-inclusive pricing with zero hidden charges, verified multilingual guides (Tamil/Telugu/Kannada/Hindi/English), and 15+ years of operations with 50,000+ satisfied pilgrims served.', 1, true),
('a5016002-0000-4000-8000-000000000002', 'cc000005-0000-4000-8000-000000000005', 'Do you have 24/7 customer support?', 'Yes! Our customer support is available 24 hours, 7 days a week, 365 days a year. During your trip, you have a dedicated trip coordinator''s number for immediate assistance. For emergencies, an escalation helpline connects you directly to a senior operations manager within 5 minutes. We also offer WhatsApp support for quick queries.', 2, true),
('a5016003-0000-4000-8000-000000000003', 'cc000005-0000-4000-8000-000000000005', 'Do you operate tours from all cities?', 'We operate pan-India with departure points from all major cities. Primary operations are from Chennai, Bengaluru, Hyderabad, Coimbatore, Madurai, Trichy, Kochi, and Mumbai. For other cities, we arrange pick-up at the nearest railway station or airport integrated into the tour. Custom packages can be designed from any starting city in India.', 3, true),
('a5016004-0000-4000-8000-000000000004', 'cc000005-0000-4000-8000-000000000005', 'How do you handle medical emergencies during tours?', 'Safety is paramount. Our guides carry first aid kits and are trained in emergency response. We have hospital tie-ups along all major tour routes. For Himalayan tours, we carry portable oxygen concentrators. In any emergency, we provide immediate first aid, arrange hospital admission, and coordinate with the patient family and insurance company. All passenger medical information provided during booking is maintained digitally.', 4, true),
('a5016005-0000-4000-8000-000000000005', 'cc000005-0000-4000-8000-000000000005', 'Do you offer solo traveler packages?', 'Yes! Solo pilgrims can join our group departure tours at the standard per-person rate. For pilgrim tours using dharamshalas, there is no single supplement. For hotel-based tours, a single supplement of 20-30% applies. We also have a solo traveler matching service to help solo travelers share accommodation costs, reducing expenses significantly.', 5, true),
('a5016006-0000-4000-8000-000000000006', 'cc000005-0000-4000-8000-000000000005', 'What languages do your guides speak?', 'Our guides speak Tamil, Telugu, Kannada, Malayalam, Hindi, and English. For Tamil Nadu temple circuits, we assign Tamil-speaking guides with deep regional knowledge. For North India tours, Hindi-speaking guides are provided with Tamil/Telugu phone interpretation support. International tour guides are English-speaking with Hindi/Tamil assistance available.', 6, true),
('a5016007-0000-4000-8000-000000000007', 'cc000005-0000-4000-8000-000000000005', 'Can I combine multiple pilgrimage circuits in one trip?', 'Yes, multi-circuit combinations are our specialty. Popular combos: Tamil Nadu Pilgrimage (Tirupati + Rameswaram + Kanyakumari + Madurai, 8 days), South India Grand Circuit (Tirupati + Rameswaram + Madurai + Guruvayur + Sabarimala, 12 days), North India Sacred Triangle (Varanasi + Prayagraj + Mathura + Vrindavan, 8 days). Custom combination tours are designed within 24 hours.', 7, true)

